这是一个基于 Python Flask 的 Web 服务器实现，复刻 provided `pickup.py` 的核心逻辑。

这个实现满足以下要求：
1.  **后端逻辑**：移植了 `ImageSelector` 类的核心功能（读取、移动、撤销、排序）[1]。
2.  **Web 界面**：专为移动端 Chrome 设计，使用 Flexbox 布局，图片自适应屏幕，按钮便于触控。
3.  **交互方式**：原有的键盘快捷键（Left, Right, Enter, Ctrl-Z, F5）已转换为页面底部的操作按钮。

### 使用说明
1.  确保已安装依赖：`pip install flask natsort pillow`
2.  修改代码中的 `SRC_DIR` 和 `DST_DIR` 为你实际的文件夹路径。
3.  运行脚本，手机连接同一 Wi-Fi，访问电脑 IP 的 5000 端口（例如 `http://192.168.1.x:5000`）。

### 代码实现 (`app.py`)

```python
import os
import shutil
from flask import Flask, render_template_string, send_file, jsonify, request
from natsort import natsorted

# 配置路径，参考源文件中的路径设置 [1]
SRC_DIR = "C:/Users/Ichinoe/Downloads/src"
DST_DIR = "C:/Users/Ichinoe/Downloads/dst"

app = Flask(__name__)

# 移植并改造 ImageSelector 逻辑以适应 Web 无状态/单例模式 [1]
class ImageSelectorWeb:
    def __init__(self, src, dst):
        self.src = src
        self.dst = dst
        self.history = []
        self.images = []
        self.index = 0

        # 确保目标文件夹存在 [1]
        os.makedirs(self.dst, exist_ok=True)
        self.reset_images()

    def reset_images(self):
        """扫描目录并使用 natsorted 排序，逻辑源自 source [1]"""
        if not os.path.exists(self.src):
            os.makedirs(self.src)

        self.index = 0
        # 过滤图片文件并排序 [1]
        self.images = natsorted([
            f for f in os.listdir(self.src)
            if f.lower().endswith((".png", ".jpg", ".jpeg"))
        ])
        self.history = []

    def get_current_info(self):
        if not self.images:
            return {"name": "No images left", "count": 0, "index": 0}
        return {
            "name": self.images[self.index],
            "count": len(self.images),
            "index": self.index + 1
        }

    def get_current_path(self):
        if not self.images:
            return None
        return os.path.join(self.src, self.images[self.index])

    def _index_delta(self, delta):
        """处理循环索引逻辑 [1]"""
        size = len(self.images)
        if size > 0:
            self.index = (self.index + delta) % size
        else:
            self.index = 0

    def _append_history(self, item):
        """记录历史操作用于撤销 [1]"""
        self.history.append(item)
        self.history = self.history[-100:]

    def next_image(self):
        if not self.images: return
        self._index_delta(1)
        # 记录索引变化以便撤销 [1]
        self._append_history(("index", 1))

    def prev_image(self):
        if not self.images: return
        self._index_delta(-1)
        self._append_history(("index", -1))

    def move_image(self):
        """对应原代码中的 enter_action [1]"""
        if not self.images: return

        current_name = self.images[self.index]
        src_file = os.path.join(self.src, current_name)
        # 规范化路径 [1]
        src_file = os.path.normpath(os.path.abspath(src_file))
        dst_file = os.path.join(self.dst, current_name)

        try:
            shutil.move(src_file, dst_file) # 移动文件 [1]

            # 记录移动操作用于撤销 [1]
            self._append_history(("move", dst_file, current_name))

            self.images.pop(self.index)
            self._index_delta(0) # 修正移除后的索引
        except Exception as e:
            print(f"Error moving file: {e}")

    def undo(self):
        """撤销逻辑，对应原代码 undo 方法 [1]"""
        if not self.history: return

        action_record = self.history.pop()
        action = action_record[0]

        if action == "index":
            step = action_record[1]
            self._index_delta(-step)

        elif action == "move":
            _, path, name = action_record
            src_file = os.path.join(self.src, name)
            try:
                # 将文件移回源目录 [1]
                shutil.move(path, src_file)
                self.images.insert(self.index, name)
            except Exception as e:
                print(f"Error undoing move: {e}")

# 初始化全局选择器实例
selector = ImageSelectorWeb(SRC_DIR, DST_DIR)

# --- Flask 路由 ---

@app.route('/')
def index():
    # 简单的移动端 HTML 模板
    return render_template_string('''
<!DOCTYPE html>
<html lang="zh">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0, maximum-scale=1.0, user-scalable=no">
    <title>Image Pickup</title>
    <style>
        body { margin: 0; padding: 0; background: #222; color: #fff; font-family: sans-serif; display: flex; flex-direction: column; height: 100vh; }
        #header { padding: 10px; text-align: center; background: #333; font-size: 14px; flex-shrink: 0;}
        #image-container { flex-grow: 1; display: flex; align-items: center; justify-content: center; overflow: hidden; position: relative; }
        #image-container img { max-width: 100%; max-height: 100%; object-fit: contain; }
        #controls { padding: 10px; background: #333; display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 8px; flex-shrink: 0; }
        .row-full { grid-column: 1 / -1; display: flex; gap: 8px;}
        button { padding: 15px 0; font-size: 16px; border: none; border-radius: 5px; color: white; font-weight: bold; cursor: pointer; touch-action: manipulation;}
        button:active { opacity: 0.7; }

        .btn-nav { background-color: #555; width: 100%; }
        .btn-pick { background-color: #28a745; width: 100%; flex-grow: 2;}
        .btn-undo { background-color: #ffc107; color: #000; flex-grow: 1;}
        .btn-reset { background-color: #dc3545; grid-column: 1 / -1;}

        .msg { position: absolute; top: 50%; left: 50%; transform: translate(-50%, -50%); color: #888;}
    </style>
</head>
<body>
    <div id="header">
        <span id="filename">Loading...</span> 
        (<span id="idx">0</span>/<span id="total">0</span>)
    </div>

    <div id="image-container">
        <img id="main-img" src="" alt="View">
        <div id="no-img-msg" class="msg" style="display:none;">No Images Left</div>
    </div>

    <div id="controls">
        <!-- 上一张 / 下一张 -->
        <div class="row-full">
            <button class="btn-nav" onclick="doAction('prev')">Prev (&larr;)</button>
            <button class="btn-nav" onclick="doAction('next')">Next (&rarr;)</button>
        </div>

        <!-- 核心操作：Pick (Enter) 和 Undo (Ctrl-z) -->
        <div class="row-full">
            <button class="btn-undo" onclick="doAction('undo')">Undo</button>
            <button class="btn-pick" onclick="doAction('pick')">PICK / SAVE</button>
        </div>

        <!-- 重置 (F5) -->
        <button class="btn-reset" onclick="doAction('reset')">Reset List</button>
    </div>

    <script>
        function updateView() {
            // 刷新图片，添加时间戳防止缓存
            const img = document.getElementById('main-img');
            const msg = document.getElementById('no-img-msg');

            fetch('/api/info')
                .then(r => r.json())
                .then(data => {
                    document.getElementById('filename').innerText = data.name;
                    document.getElementById('idx').innerText = data.index;
                    document.getElementById('total').innerText = data.count;

                    if (data.count === 0) {
                        img.style.display = 'none';
                        msg.style.display = 'block';
                    } else {
                        img.style.display = 'block';
                        msg.style.display = 'none';
                        // 只有当文件名变了才请求新图片，或者强制刷新
                        img.src = `/api/img?t=${new Date().getTime()}`;
                    }
                });
        }

        function doAction(action) {
            fetch(`/api/${action}`, { method: 'POST' })
                .then(() => updateView());
        }

        // 初始化
        updateView();
    </script>
