class ImageSelectorWeb:
    def __init__(self, src, dst):
        self.src = src
        self.dst = dst
        self.history = []
        self.images = []
        self.index = 0

        os.makedirs(self.dst, exist_ok=True)
        self.reset_images()

    def reset_images(self):
        if not os.path.exists(self.src):
            os.makedirs(self.src)

        self.index = 0
        self.images = natsorted([
            f for f in os.listdir(self.src)
            if f.lower().endswith((".png", ".jpg", ".jpeg", ".gif", ".webp"))
        ])
        self.history = []

    def get_current_info(self):
        if not self.images:
            return {"name": "No images left", "count": 0, "index": 0}
        return {
            "name": self.images[self.index],
            "count": len(self.images),
            "index": self.index + 1
        }

    def get_current_path(self):
        if not self.images:
            return None
        return os.path.join(self.src, self.images[self.index])

    def _index_delta(self, delta):
        size = len(self.images)
        if size > 0:
            self.index = (self.index + delta) % size
        else:
            self.index = 0

    def _append_history(self, item):
        self.history.append(item)
        self.history = self.history[-100:]

    def next_image(self):
        if not self.images: return
        self._index_delta(1)
        self._append_history(("index", 1))

    def prev_image(self):
        if not self.images: return
        self._index_delta(-1)
        self._append_history(("index", -1))

    def move_image(self):
        if not self.images: return

        current_name = self.images[self.index]
        src_file = os.path.join(self.src, current_name)
        src_file = os.path.normpath(os.path.abspath(src_file))
        dst_file = os.path.join(self.dst, current_name)

        try:
            shutil.move(src_file, dst_file)
            self._append_history(("move", dst_file, current_name))
            self.images.pop(self.index)
            self._index_delta(0)
        except Exception as e:
            print(f"Error moving file: {e}")

    def undo(self):
        if not self.history: return

        action_record = self.history.pop()
        action = action_record[0]

        if action == "index":
            step = action_record[1]
            self._index_delta(-step)

        elif action == "move":
            _, path, name = action_record
            src_file = os.path.join(self.src, name)
            try:
                shutil.move(path, src_file)
                self.images.insert(self.index, name)
            except Exception as e:
                print(f"Error undoing move: {e}")

